def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject (most common subject across all triples)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Collect all information for the main subject
    info_parts = []

    for t in triples:
        if t.subject == main_subject:
            pred = t.predicate
            obj = t.object

            if pred == "birthPlace":
                info_parts.append(f"born in {obj}")
            elif pred == "birthDate":
                info_parts.append(f"born on {obj}")
            elif pred == "birthYear":
                info_parts.append(f"born in {obj}")
            elif pred == "deathPlace":
                info_parts.append(f"died in {obj}")
            elif pred == "deathDate":
                info_parts.append(f"died on {obj}")
            elif pred == "deathYear":
                info_parts.append(f"died in {obj}")
            elif pred == "nationality":
                info_parts.append(f"{obj} national")
            elif pred == "party":
                info_parts.append(f"member of the {obj} party")
            elif pred == "office":
                info_parts.append(f"held the office of {obj}")
            elif pred == "successor":
                info_parts.append(f"succeeded by {obj}")
            elif pred == "predecessor":
                info_parts.append(f"preceded by {obj}")
            elif pred == "spouse":
                info_parts.append(f"married to {obj}")
            elif pred == "residence":
                info_parts.append(f"resides at {obj}")
            elif pred == "region":
                info_parts.append(f"from the region of {obj}")
            elif pred == "country":
                info_parts.append(f"from {obj}")
            elif pred == "capital":
                info_parts.append(f"whose capital is {obj}")
            elif pred == "largestCity":
                info_parts.append(f"with largest city {obj}")
            elif pred == "currency":
                info_parts.append(f"using {obj} currency")
            elif pred == "language":
                info_parts.append(f"where {obj} is spoken")
            elif pred == "officialLanguage":
                info_parts.append(f"with official language {obj}")
            elif pred == "leader":
                info_parts.append(f"led by {obj}")
            elif pred == "battle":
                info_parts.append(f"participated in the {obj}")
            elif pred == "almaMater":
                info_parts.append(f"studied at {obj}")
            elif pred == "profession":
                info_parts.append(f"worked as a {obj}")
            elif pred == "religion":
                info_parts.append(f"follows {obj}")
            elif pred == "militaryBranch":
                info_parts.append(f"served in the {obj}")
            elif pred == "militaryRank":
                info_parts.append(f"held the rank of {obj}")
            elif pred == "state":
                info_parts.append(f"from {obj}")
            elif pred == "award":
                info_parts.append(f"received the {obj}")
            elif pred == "activeYearsStartDate":
                info_parts.append(f"started in {obj}")
            elif pred == "activeYearsEndDate":
                info_parts.append(f"ended in {obj}")
            else:
                info_parts.append(f"{pred} {obj}")

    # Build final sentence
    if info_parts:
        return f"{main_subject} is " + ", ".join(info_parts[:-1]) + " and " + info_parts[-1] if len(info_parts) > 1 else f"{main_subject} is {info_parts[0]}" + "."

    return ""

